}

template <typename T>
cl_mem alloc(int N){
	cl_mem mem_d = _clMalloc((int)(sizeof(T)*N));
	return mem_d;
}

template <typename T>
void dealloc(cl_mem array){
	_clFree(array);
}

template <typename T>
void copy(cl_mem dst, cl_mem src, int N){
	_clMemcpyD2D(dst, src, (int)(N*sizeof(T)));
}

template <typename T>
void upload(cl_mem dst, T* src, int N){
	_clMemcpyH2D(dst, src, (int)(N*sizeof(T)));
}

template <typename T>
void download(T* dst, cl_mem src, int N){
	_clMemcpyD2H(dst, src, (int)(N*sizeof(T)));
}

